          import sailpoint.object.Identity;
          import sailpoint.tools.Util;
          boolean flag = false;
          if(identity!=null){

          String ministry = identity.getStringAttribute("ministry");
          String type = identity.getStringAttribute("type");

          if(Util.isNotNullOrEmpty(ministry) && Util.isNotNullOrEmpty(type) && !Util.nullSafeCaseInsensitiveEq("non-hr contractor",type)){
          flag = true;
          }

          }
          return flag;
